const toBool = v => ['true','yes','1',true,1].includes(typeof v === 'string' ? v.toLowerCase().trim() : v);
const normalise = r => ({ json: {
  name: String(r.name || r.Name || '').trim(),
  age: parseInt(r.age || r.Age, 10),
  marital_status: String(r.marital_status || r.Marital_Status || r['Marital Status'] || '').trim(),
  has_children: toBool(r.has_children ?? r.Has_Children ?? r['Has Children']),
  owns_property: toBool(r.owns_property ?? r.Owns_Property ?? r['Owns Property']),
  has_business: toBool(r.has_business ?? r.Has_Business ?? r['Has Business'])
}});
const results = [];
for (const item of $input.all()) {
  const r = item.json;
  if (r.data && Array.isArray(r.data)) { results.push(...r.data.map(normalise)); }
  else { results.push(normalise(r)); }
}
return results;

const f = $input.first().json;
const toBool = v => v === 'Yes' || v === true || v === 'true' || v === '1';
return [{ json: {
  name: String(f.name || '').trim(),
  age: parseInt(f.age, 10) || 0,
  marital_status: String(f.marital_status || '').trim(),
  has_children: toBool(f.has_children),
  owns_property: toBool(f.owns_property),
  has_business: toBool(f.has_business)
}}];

return $input.all().map(item => {
  const client = item.json;

  const systemPrompt = `You are an expert estate planning advisor with 20 years of experience. Your role is to analyze client profiles and recommend appropriate legal instruments for their estate plan. You must respond ONLY with valid JSON — no markdown code blocks, no preamble, no explanation outside the JSON. Your response must be a single valid JSON object.`;

  const userPrompt = `Analyze this client and recommend estate planning instruments.

CLIENT PROFILE:
- Name: ${client.name}
- Age: ${client.age} years old
- Marital Status: ${client.marital_status}
- Has Dependent Children: ${client.has_children}
- Owns Real Property: ${client.owns_property}
- Owns a Business: ${client.has_business}

AVAILABLE INSTRUMENTS (select all that apply):
- Last Will and Testament
- Revocable Living Trust
- Irrevocable Trust
- Healthcare Directive (Living Will)
- Durable Power of Attorney (Healthcare)
- Financial Power of Attorney
- Beneficiary Designations Review
- Business Succession Plan
- Guardianship Designation
- Pour-Over Will

URGENCY GUIDELINES:
- High: Client is age 65+, OR owns a business alongside other assets, OR has minor children with significant assets
- Medium: Client has 2+ complicating factors (e.g., divorced + children, or married + property without other planning)
- Low: Client is young (under 40), single, no dependents, minimal assets

Respond with exactly this JSON (no other text):
{
  "client_name": "${client.name}",
  "recommended_instruments": ["instrument1", "instrument2"],
  "rationale": "1-3 sentences explaining the specific recommendation for this client",
  "urgency_flag": "High or Medium or Low"
}`;

  const groq_body = {
    model: 'llama-3.3-70b-versatile',
    temperature: 0.1,
    max_tokens: 500,
    messages: [
      { role: 'system', content: systemPrompt },
      { role: 'user', content: userPrompt }
    ]
  };

  return { json: { ...client, system_prompt: systemPrompt, user_prompt: userPrompt, groq_body } };
});

return $input.all().map((item, i) => {
  const data = item.json;
  const promptData = $('Build LLM Prompt').all()[i]?.json || {};

  const rawResponse = data.choices[0].message.content;
  let parsed;

  try {
    parsed = JSON.parse(rawResponse);
  } catch (e) {
    const match = rawResponse.match(/\{[\s\S]*\}/);
    if (match) {
      parsed = JSON.parse(match[0]);
    } else {
      throw new Error(`Cannot parse LLM response: ${rawResponse}`);
    }
  }

  const required = ['client_name', 'recommended_instruments', 'rationale', 'urgency_flag'];
  for (const field of required) {
    if (!parsed[field]) throw new Error(`Missing field "${field}" in LLM response for item ${i}`);
  }

  if (!['High', 'Medium', 'Low'].includes(parsed.urgency_flag)) {
    throw new Error(`Invalid urgency_flag "${parsed.urgency_flag}" — expected High / Medium / Low`);
  }

  return {
    json: {
      client_name: parsed.client_name,
      recommended_instruments: parsed.recommended_instruments,
      rationale: parsed.rationale,
      urgency_flag: parsed.urgency_flag,
      _input: {
        name: promptData.name,
        age: promptData.age,
        marital_status: promptData.marital_status,
        has_children: promptData.has_children,
        owns_property: promptData.owns_property,
        has_business: promptData.has_business
      },
      _system_prompt: promptData.system_prompt,
      _user_prompt: promptData.user_prompt,
      _raw_response: rawResponse
    }
  };
});

const allClients = $input.first().json.clients;

const sampleOutput = allClients.map(c => ({
  client_name: c.client_name,
  recommended_instruments: c.recommended_instruments,
  rationale: c.rationale,
  urgency_flag: c.urgency_flag
}));

const evidenceData = allClients.map(c => ({
  input_data: c._input,
  prompt_sent: { system: c._system_prompt, user: c._user_prompt },
  raw_llm_response: c._raw_response,
  parsed_output: {
    client_name: c.client_name,
    recommended_instruments: c.recommended_instruments,
    rationale: c.rationale,
    urgency_flag: c.urgency_flag
  }
}));

return [{ json: { sample_output: sampleOutput, evidence_data: evidenceData } }];
